// Parse CS Insider Notion job board - v1.3: Handle /scrape response
const response = $input.first().json;

// /scrape returns { data: [{ results: [{ html: '...' }] }] }
let html = '';
if (response.data && response.data[0] && response.data[0].results) {
  html = response.data[0].results.map(r => r.html || r.text || '').join('\n');
} else if (typeof response === 'string') {
  html = response;
} else {
  html = JSON.stringify(response);
}

const jobs = [];
const today = new Date().toISOString().split('T')[0];

console.log('HTML length:', html.length);

// Multiple patterns for company extraction
const companyPatterns = [
  /Company<\/span>:?\s*([^<]+)/gi,
  /Company[:\s]+([A-Z][a-zA-Z0-9\s&.-]+?)(?:<|\/|$)/gi
];

const companyMatches = [];
for (const pattern of companyPatterns) {
  let match;
  while ((match = pattern.exec(html)) !== null) {
    const company = match[1].trim();
    if (company.length > 1 && company.length < 100 && !companyMatches.includes(company)) {
      companyMatches.push(company);
    }
  }
  if (companyMatches.length > 0) break;
}

// Location patterns
const locationPatterns = [
  /Location<\/span>:?\s*([^<]+)/gi,
  /Location[:\s]+([A-Za-z][a-zA-Z,\s.-]+?)(?:<|\/|$)/gi
];

const locationMatches = [];
for (const pattern of locationPatterns) {
  let match;
  while ((match = pattern.exec(html)) !== null) {
    const loc = match[1].trim();
    if (loc.length > 1 && loc.length < 100 && !locationMatches.includes(loc)) {
      locationMatches.push(loc);
    }
  }
  if (locationMatches.length > 0) break;
}

// Extract apply links
const applyRegex = /href="(https:\/\/[^"]*(?:greenhouse|lever|workday|ashby|jobs\.|careers|apply|hiring)[^"]*)"/gi;
const applyMatches = [];
let applyMatch;
while ((applyMatch = applyRegex.exec(html)) !== null) {
  const url = applyMatch[1];
  if (!url.includes('notion.') && !url.includes('google.com') && !applyMatches.includes(url)) {
    applyMatches.push(url);
  }
}

// Extract job titles
const titlePattern = />([^<]*(?:Customer Success|CSM|Client Success|Account Manager|Success Manager|Engagement Manager|Implementation|Onboarding)[^<]*)</gi;
const cleanTitles = [];
let titleMatch;
while ((titleMatch = titlePattern.exec(html)) !== null) {
  const title = titleMatch[1].trim();
  if (title.length > 5 && title.length < 100 && !cleanTitles.includes(title)) {
    cleanTitles.push(title);
  }
}

// Helper to generate Job ID
function extractJobId(url) {
  const patterns = [
    /\/jobs?\/([a-f0-9-]+)/i,
    /\/postings?\/([a-f0-9-]+)/i,
    /job_id=([a-f0-9-]+)/i,
    /\/([0-9]+)(?:\?|$)/
  ];
  for (const pattern of patterns) {
    const match = url.match(pattern);
    if (match) return match[1];
  }
  let hash = 0;
  for (let i = 0; i < url.length; i++) {
    hash = ((hash << 5) - hash) + url.charCodeAt(i);
    hash = hash & hash;
  }
  return 'csi-' + Math.abs(hash).toString(36);
}

// Build job objects
for (let i = 0; i < applyMatches.length; i++) {
  const company = companyMatches[i];
  const title = cleanTitles[i];
  const jobUrl = applyMatches[i];

  if (jobUrl && company) {
    jobs.push({
      json: {
        'Job Title': title || 'Customer Success Manager',
        'Company': company,
        'Location': locationMatches[i] || 'Remote',
        'Job URL': jobUrl,
        'Source': 'CS Insider',
        'Date Found': today,
        'Job ID': extractJobId(jobUrl)
      }
    });
  }
}

console.log('=== CS INSIDER SCRAPE SUMMARY ===');
console.log('Jobs:', jobs.length, 'Companies:', companyMatches.length, 'URLs:', applyMatches.length);

if (jobs.length === 0) {
  return [{
    json: {
      error: 'No jobs parsed',
      debug: {
        htmlLength: html.length,
        companiesFound: companyMatches.length,
        sampleCompanies: companyMatches.slice(0, 5),
        titlesFound: cleanTitles.length,
        sampleTitles: cleanTitles.slice(0, 5),
        applyLinksFound: applyMatches.length,
        sampleUrls: applyMatches.slice(0, 5),
        htmlSample: html.substring(0, 3000)
      }
    }
  }];
}

return jobs;
